#include "adc_dma.h"
#include <driver/adc.h>
static uint8_t _pin=36;
void adc_dma_setup(uint8_t p,uint32_t sr){_pin=p;analogReadResolution(12);Serial.printf("[adc_dma] OK pin=%d rate=%lu\n",p,(unsigned long)sr);}
void adc_dma_read(int16_t*buf,size_t n){for(size_t i=0;i<n;i++)buf[i]=analogRead(_pin);}
float adc_dma_get_max(){float mx=0;for(int i=0;i<64;i++){float v=analogRead(_pin);if(v>mx)mx=v;}return mx*3.3/4095.0;}
float adc_dma_get_rms(){float sum=0;for(int i=0;i<64;i++){float v=analogRead(_pin);sum+=v*v;}return sqrt(sum/64)*3.3/4095.0;}
